/*
 * Circular Queue Implementation in C
 * university 2022 Scheme - Data Structures (18CS34)
 * Topic: Circular Queues
 * 
 * This implementation uses array representation with two pointers:
 * front and rear. Demonstrates modular arithmetic for circular behavior.
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAXSIZE 5 // Queue capacity (max elements = MAXSIZE - 1)

/* Structure definition for Circular Queue */
typedef struct {
 int items[MAXSIZE]; // Array to store queue elements
 int front; // Index of front element
 int rear; // Index of rear element
 int capacity; // Maximum queue size
} CircularQueue;

/* Function to initialize the queue */
void initialize(CircularQueue *q) {
 q->capacity = MAXSIZE;
 q->front = -1; // -1 indicates empty queue
 q->rear = -1;
}

/* Check if queue is empty */
isEmpty(CircularQueue *q) {
 return (q->front == -1 && q->rear == -1);
}

/* Check if queue is full */
isFull(CircularQueue *q) {
 // Queue is full when next rear position equals front
 // This design sacrifices one slot to distinguish full from empty
 return ((q->rear + 1) % q->capacity == q->front);
}

/* Enqueue - Add element to rear of queue */
/* Returns 1 on success, 0 on failure */
int enqueue(CircularQueue *q, int value) {
 if (isFull(q)) {
 printf("Queue Overflow! Cannot enqueue %d. Queue is full.\n", value);
 return 0;
 }

 /* If queue is empty, initialize both front and rear */
 if (isEmpty(q)) {
 q->front = 0;
 q->rear = 0;
 } else {
 /* Circular increment using modulo operator */
 /* Wraps from last index back to index 0 */
 q->rear = (q->rear + 1) % q->capacity;
 }

 q->items[q->rear] = value;
 printf("Enqueued: %d | Front=%d, Rear=%d\n", value, q->front, q->rear);
 return 1;
}

/* Dequeue - Remove and return element from front of queue */
/* Returns the dequeued element or -1 on underflow */
int dequeue(CircularQueue *q) {
 int item;

 if (isEmpty(q)) {
 printf("Queue Underflow! Queue is empty.\n");
 return -1;
 }

 /* Store the front element */
 item = q->items[q->front];

 /* If only one element exists, reset queue to empty state */
 if (q->front == q->rear) {
 q->front = -1;
 q->rear = -1;
 } else {
 /* Circular increment using modulo operator */
 q->front = (q->front + 1) % q->capacity;
 }

 printf("Dequeued: %d | Front=%d, Rear=%d\n", item, q->front, q->rear);
 return item;
}

/* Peek - View front element without removing */
int peek(CircularQueue *q) {
 if (isEmpty(q)) {
 printf("Queue is empty.\n");
 return -1;
 }
 return q->items[q->front];
}

/* Get rear element without removing */
int getRear(CircularQueue *q) {
 if (isEmpty(q)) {
 printf("Queue is empty.\n");
 return -1;
 }
 return q->items[q->rear];
}

/* Display queue contents */
void display(CircularQueue *q) {
 int i;

 if (isEmpty(q)) {
 printf("Queue: EMPTY\n");
 return;
 }

 printf("Queue Contents: ");

 /* Handle both normal and wrap-around cases */
 if (q->front <= q->rear) {
 /* Normal traversal: front <= rear */
 for (i = q->front; i <= q->rear; i++) {
 printf("[%d] ", q->items[i]);
 }
 } else {
 /* Wrap-around case: front > rear */
 for (i = q->front; i < q->capacity; i++) {
 printf("[%d] ", q->items[i]);
 }
 for (i = 0; i <= q->rear; i++) {
 printf("[%d] ", q->items[i]);
 }
 }
 printf("\n");
 printf("Front index: %d, Rear index: %d\n", q->front, q->rear);
}

/* Main function demonstrating circular queue operations */
int main() {
 CircularQueue q;
 int choice, value;

 initialize(&q);

 printf("========================================\n");
 printf("CIRCULAR QUEUE - C IMPLEMENTATION\n");
 printf("========================================\n");

 /* Demonstrate step-by-step operations */
 printf("\n--- Adding 10, 20, 30 ---\n");
 enqueue(&q, 10); // front=0, rear=0
 enqueue(&q, 20); // front=0, rear=1
 enqueue(&q, 30); // front=0, rear=2
 display(&q);

 printf("\n--- Removing 2 elements ---\n");
 dequeue(&q); // Returns 10, front moves to 1
 dequeue(&q); // Returns 20, front moves to 2
 display(&q);
 printf("Note: Indices 0,1 are now available for reuse!\n");

 printf("\n--- Adding 40, 50, 60 (wrap-around demo) ---\n");
 enqueue(&q, 40); // rear becomes 3
 enqueue(&q, 50); // rear becomes 4
 enqueue(&q, 60); // rear wraps to 0, queue becomes FULL
 display(&q);

 printf("\n--- Checking Status ---\n");
 printf("Is Empty: %s\n", isEmpty(&q) ? "Yes" : "No");
 printf("Is Full: %s\n", isFull(&q) ? "Yes" : "No");

 printf("\n--- Peek Operations ---\n");
 printf("Front element (peek): %d\n", peek(&q));
 printf("Rear element: %d\n", getRear(&q));

 printf("\n--- Overflow Demonstration ---\n");
 enqueue(&q, 70); // Should fail - queue overflow

 printf("\n--- Emptying the Queue ---\n");
 while (!isEmpty(&q)) {
 dequeue(&q);
 }
 display(&q);

 printf("\n--- Underflow Demonstration ---\n");
 dequeue(&q); // Should fail - queue underflow

 printf("\n========================================\n");
 printf("TIME COMPLEXITY: All operations O(1)\n");
 printf("========================================\n");

 return 0;
}

/*
 * university EXAM NOTES:
 * ----------------
 * 1. Circular queue solves memory wastage problem of linear queues
 * 2. Formula for circular increment: index = (index + 1) % capacity
 * 3. isEmpty condition: front == -1 && rear == -1
 * 4. isFull condition: (rear + 1) % capacity == front
 * 5. Maximum elements = capacity - 1 (one slot sacrificed)
 * 6. All operations take O(1) time
 */
